// ── DS: GLOBAL CSS (endast för det som inline-style inte kan uttrycka: pseudo-klasser) ──
// Detta injiceras EN gång via <DSGlobalStyles/>. Ingen befintlig vy renderar den ännu.
function DSGlobalStyles() {
  return <style>{`
    .ds-btn:not(:disabled):hover { filter:brightness(0.96); transform:translateY(-1px); }
    .ds-btn:not(:disabled):active { transform:translateY(0); filter:brightness(0.92); }
    .ds-btn:focus-visible, .ds-iconbtn:focus-visible { outline:2px solid ${tokens.color.accent}; outline-offset:2px; }
    .ds-btn:disabled { opacity:${tokens.alpha.disabled}; cursor:not-allowed; transform:none !important; }
    .ds-field:focus { outline:none; border-color:${tokens.color.accent} !important; box-shadow:0 0 0 3px ${tokens.alpha.focusRing}; }
    .ds-card-hoverable:hover { box-shadow:${tokens.shadow.md}; transform:translateY(-2px); }
    .ds-sidebar-item:hover:not(.ds-sidebar-item--active) { background:${tokens.alpha.hoverOnDark}; color:#fff; }
    .ds-fade-in { animation: ds-fade .18s ease; }
    @keyframes ds-fade { from{opacity:0; transform:translateY(2px);} to{opacity:1; transform:translateY(0);} }
    @keyframes ds-spin { to{ transform:rotate(360deg); } }
    @keyframes ds-skeleton { 0%{opacity:.6;} 50%{opacity:1;} 100%{opacity:.6;} }
  `}</style>;
}

// ── DS: BUTTON ────────────────────────────────────────────────────────────────
// Varianter: primary | secondary | ghost | danger. Storlekar: sm | md | lg.
// Ersätter (i Steg 2) de 58 fria btnStyle(hexfärg)-anropen med semantik istället för hårdkodad hex.
function DSButton({ variant="primary", size="md", icon, loading=false, disabled=false, children, onClick, style, type="button" }) {
  const variants = {
    primary:   { bg: tokens.color.primary, color:"#fff", border:"none" },
    secondary: { bg: tokens.color.surface, color: tokens.color.text, border:`1px solid ${tokens.color.border}` },
    ghost:     { bg: "transparent", color: tokens.color.text, border:"none" },
    danger:    { bg: tokens.color.error, color:"#fff", border:"none" },
  };
  const sizes = {
    sm: { padding:"6px 12px", fontSize: tokens.font.size.xs, radius: tokens.radius.sm },
    md: { padding:"11px 20px", fontSize: tokens.font.size.base, radius: tokens.radius.md },
    lg: { padding:"14px 28px", fontSize: tokens.font.size.lg, radius: tokens.radius.md },
  };
  const v = variants[variant] || variants.primary;
  const s = sizes[size] || sizes.md;
  return <button
    type={type}
    className="ds-btn"
    disabled={disabled || loading}
    onClick={onClick}
    style={{
      background:v.bg, color:v.color, border:v.border, borderRadius:s.radius, padding:s.padding,
      fontSize:s.fontSize, fontFamily:tokens.font.family, fontWeight:tokens.font.weight.semibold,
      cursor: disabled||loading ? "not-allowed":"pointer", transition:"all .15s ease",
      display:"inline-flex", alignItems:"center", gap:8, ...style,
    }}
  >
    {loading ? <DSSpinner size={14} color={v.color} /> : icon}
    {children}
  </button>;
}

// ── DS: ICON BUTTON ───────────────────────────────────────────────────────────
function DSIconButton({ icon, onClick, size=32, title, disabled=false }) {
  return <button
    className="ds-iconbtn" title={title} disabled={disabled} onClick={onClick}
    style={{
      width:size, height:size, display:"inline-flex", alignItems:"center", justifyContent:"center",
      background:"transparent", border:"none", borderRadius:tokens.radius.sm, cursor: disabled?"not-allowed":"pointer",
      fontSize:16, color:tokens.color.textMuted, transition:"background .12s ease",
    }}
    onMouseEnter={e=>!disabled&&(e.currentTarget.style.background="#f1f5f9")}
    onMouseLeave={e=>e.currentTarget.style.background="transparent"}
  >{icon}</button>;
}

// ── DS: FORM FIELDS (Input, Textarea, Select, Checkbox, Switch) ─────────────────
function DSLabel({ children }) {
  return <label style={{ display:"block", fontSize:tokens.font.size.xs, fontWeight:tokens.font.weight.semibold, color:tokens.color.textMuted, textTransform:"uppercase", letterSpacing:tokens.font.tracking.wide, marginBottom:6 }}>{children}</label>;
}
function DSHelperText({ children, error }) {
  return <div style={{ fontSize:tokens.font.size.xs, color: error?tokens.color.error:tokens.color.textMuted, marginTop:4 }}>{children}</div>;
}
function fieldBaseStyle() {
  return { width:"100%", padding:"10px 12px", borderRadius:tokens.radius.sm, border:`1px solid ${tokens.color.border}`, fontSize:tokens.font.size.base, fontFamily:tokens.font.family, color:tokens.color.text, boxSizing:"border-box", transition:"border-color .12s ease" };
}
function DSInput({ label, helper, error, id, ...props }) {
  const fid = id || label?.replace(/\s+/g,"-").toLowerCase();
  return <div style={{ marginBottom:16 }}>
    {label && <DSLabel htmlFor={fid}>{label}</DSLabel>}
    <input id={fid} className="ds-field" style={{ ...fieldBaseStyle(), borderColor: error?tokens.color.error:tokens.color.border }} {...props} />
    {(helper||error) && <DSHelperText error={!!error}>{error || helper}</DSHelperText>}
  </div>;
}
function DSTextarea({ label, helper, error, id, rows=4, ...props }) {
  const fid = id || label?.replace(/\s+/g,"-").toLowerCase();
  return <div style={{ marginBottom:16 }}>
    {label && <DSLabel htmlFor={fid}>{label}</DSLabel>}
    <textarea id={fid} rows={rows} className="ds-field" style={{ ...fieldBaseStyle(), resize:"vertical" }} {...props} />
    {(helper||error) && <DSHelperText error={!!error}>{error || helper}</DSHelperText>}
  </div>;
}
function DSSelect({ label, helper, error, id, children, ...props }) {
  const fid = id || label?.replace(/\s+/g,"-").toLowerCase();
  return <div style={{ marginBottom:16 }}>
    {label && <DSLabel htmlFor={fid}>{label}</DSLabel>}
    <select id={fid} className="ds-field" style={{ ...fieldBaseStyle(), background:"#fff" }} {...props}>{children}</select>
    {(helper||error) && <DSHelperText error={!!error}>{error || helper}</DSHelperText>}
  </div>;
}
function DSCheckbox({ label, checked, onChange, id }) {
  const fid = id || label?.replace(/\s+/g,"-").toLowerCase();
  return <label htmlFor={fid} style={{ display:"flex", alignItems:"center", gap:8, fontSize:tokens.font.size.base, color:tokens.color.text, cursor:"pointer", marginBottom:10 }}>
    <input id={fid} type="checkbox" checked={checked} onChange={onChange} style={{ width:18, height:18, accentColor:tokens.color.accent }} />
    {label}
  </label>;
}
function DSSwitch({ checked, onChange, label }) {
  return <label style={{ display:"flex", alignItems:"center", gap:10, cursor:"pointer" }}>
    <span onClick={()=>onChange(!checked)} style={{ width:38, height:22, borderRadius:999, background: checked?tokens.color.accent:"#cbd5e1", position:"relative", transition:"background .15s ease" }}>
      <span style={{ position:"absolute", top:2, left: checked?18:2, width:18, height:18, borderRadius:"50%", background:"#fff", transition:"left .15s ease", boxShadow:tokens.shadow.sm }} />
    </span>
    {label && <span style={{ fontSize:tokens.font.size.base, color:tokens.color.text }}>{label}</span>}
  </label>;
}

// ── DS: CARD (med Header / Content / Footer) ──────────────────────────────────
function DSCard({ children, hoverable=false, style }) {
  return <div className={hoverable ? "ds-card-hoverable" : ""} style={{ background:tokens.color.surface, border:`1px solid ${tokens.color.border}`, borderRadius:tokens.radius.lg, boxShadow:tokens.shadow.sm, transition:"all .2s ease", ...style }}>{children}</div>;
}
DSCard.Header = function DSCardHeader({ title, icon, action }) {
  return <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"20px 24px", borderBottom:`1px solid ${tokens.color.border}` }}>
    <h3 style={{ margin:0, fontSize:tokens.font.size.xl, fontWeight:tokens.font.weight.bold, color:tokens.color.text, display:"flex", alignItems:"center", gap:8 }}>{icon}{title}</h3>
    {action && <span style={{ fontSize:tokens.font.size.sm, color:tokens.color.accent, fontWeight:tokens.font.weight.semibold, cursor:"pointer" }}>{action}</span>}
  </div>;
};
DSCard.Content = function DSCardContent({ children, style }) {
  return <div style={{ padding:24, ...style }}>{children}</div>;
};
DSCard.Footer = function DSCardFooter({ children }) {
  return <div style={{ padding:"16px 24px", borderTop:`1px solid ${tokens.color.border}`, display:"flex", gap:12, justifyContent:"flex-end" }}>{children}</div>;
};

// ── DS: BADGE (fem semantiska varianter, INTE fri hex) ────────────────────────
function DSBadge({ variant="neutral", children }) {
  const map = {
    success: { bg:"#F0FDF4", color:tokens.color.accent },
    warning: { bg:"#FFF7ED", color:tokens.color.warning },
    error:   { bg:"#FEF2F2", color:tokens.color.error },
    info:    { bg:"#EFF6FF", color:tokens.color.info },
    neutral: { bg:"#F1F5F9", color:tokens.color.textMuted },
  };
  const c = map[variant] || map.neutral;
  return <span style={{ display:"inline-flex", alignItems:"center", background:c.bg, color:c.color, borderRadius:tokens.radius.full, padding:"4px 12px", fontSize:tokens.font.size.xs, fontWeight:tokens.font.weight.semibold }}>{children}</span>;
}

// ── DS: AVATAR / DIVIDER ───────────────────────────────────────────────────────
function DSAvatar({ name="", size=40 }) {
  const initials = name.split(" ").filter(Boolean).slice(0,2).map(w=>w[0]?.toUpperCase()).join("");
  return <div style={{ width:size, height:size, borderRadius:"50%", background:"#ECFDF5", color:tokens.color.primary, display:"flex", alignItems:"center", justifyContent:"center", fontWeight:tokens.font.weight.bold, fontSize:size*0.36, flexShrink:0 }}>{initials || "?"}</div>;
}
function DSDivider({ margin=16 }) {
  return <div style={{ height:1, background:tokens.color.border, margin:`${margin}px 0` }} />;
}

// ── DS: SPINNER / SKELETON ─────────────────────────────────────────────────────
function DSSpinner({ size=24, color=tokens.color.accent }) {
  return <div style={{ width:size, height:size, border:`3px solid ${color}33`, borderTop:`3px solid ${color}`, borderRadius:"50%", animation:"ds-spin 0.7s linear infinite" }} />;
}
function DSSkeleton({ width="100%", height=16 }) {
  return <div style={{ width, height, borderRadius:tokens.radius.xs, background:"#E2E8F0", animation:"ds-skeleton 1.4s ease-in-out infinite" }} />;
}

// ── DS: ALERT ──────────────────────────────────────────────────────────────────
function DSAlert({ variant="info", title, children }) {
  const map = {
    info:    { bg:"#EFF6FF", border:"#BFDBFE", color:tokens.color.info },
    success: { bg:"#F0FDF4", border:"#BBF7D0", color:tokens.color.accent },
    warning: { bg:"#FFF7ED", border:"#FED7AA", color:tokens.color.warning },
    error:   { bg:"#FEF2F2", border:"#FECACA", color:tokens.color.error },
  };
  const c = map[variant] || map.info;
  return <div style={{ background:c.bg, border:`1px solid ${c.border}`, borderRadius:tokens.radius.md, padding:"14px 16px", display:"flex", gap:12, alignItems:"flex-start" }}>
    <div style={{ width:8, height:8, borderRadius:"50%", background:c.color, marginTop:6, flexShrink:0 }} />
    <div>
      {title && <div style={{ fontWeight:tokens.font.weight.semibold, color:tokens.color.text, marginBottom:2, fontSize:tokens.font.size.base }}>{title}</div>}
      <div style={{ fontSize:tokens.font.size.sm, color:tokens.color.textMuted }}>{children}</div>
    </div>
  </div>;
}

// ── DS: EMPTY STATE ────────────────────────────────────────────────────────────
function DSEmptyState({ icon=<Search size={14} style={{verticalAlign:"-2px"}}/>, title, description, actionLabel, onAction }) {
  return <div style={{ textAlign:"center", padding:"48px 24px" }}>
    <div style={{ fontSize:40, marginBottom:12 }}>{icon}</div>
    {title && <div style={{ fontWeight:tokens.font.weight.semibold, color:tokens.color.text, marginBottom:4 }}>{title}</div>}
    {description && <div style={{ fontSize:tokens.font.size.sm, color:tokens.color.textMuted }}>{description}</div>}
    {actionLabel && <div style={{ marginTop:16 }}><DSButton onClick={onAction}>{actionLabel}</DSButton></div>}
  </div>;
}

// ── DS: MODAL / DIALOG ─────────────────────────────────────────────────────────
function DSModal({ title, children, onClose, size="md" }) {
  const widths = { sm:400, md:520, lg:720 };
  return <div style={{ position:"fixed", inset:0, background:tokens.alpha.overlay, display:"flex", alignItems:"center", justifyContent:"center", zIndex:tokens.zIndex.modal, padding:20 }} onClick={onClose}>
    <div className="ds-fade-in" onClick={e=>e.stopPropagation()} style={{ background:"#fff", borderRadius:tokens.radius.xl, padding:28, width:"100%", maxWidth:widths[size]||widths.md, maxHeight:"90vh", overflowY:"auto", boxShadow:tokens.shadow.xl }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:20 }}>
        <h3 style={{ fontSize:tokens.font.size.xl, fontWeight:tokens.font.weight.bold, color:tokens.color.text, margin:0 }}>{title}</h3>
        <DSIconButton icon={<X size={14} style={{verticalAlign:"-2px"}}/>} onClick={onClose} title="Stäng" />
      </div>
      {children}
    </div>
  </div>;
}
// DSDialog: tunn variant av DSModal för bekräftelser (framtida ersättare för window.confirm — inte kopplad än, se DDD §5.3)
function DSDialog({ title, description, confirmLabel="Bekräfta", cancelLabel="Avbryt", danger=false, onConfirm, onCancel }) {
  return <DSModal title={title} onClose={onCancel} size="sm">
    {description && <p style={{ fontSize:tokens.font.size.base, color:tokens.color.textMuted, marginTop:0 }}>{description}</p>}
    <div style={{ display:"flex", gap:10, justifyContent:"flex-end", marginTop:20 }}>
      <DSButton variant="secondary" onClick={onCancel}>{cancelLabel}</DSButton>
      <DSButton variant={danger?"danger":"primary"} onClick={onConfirm}>{confirmLabel}</DSButton>
    </div>
  </DSModal>;
}

// ── DS: TOOLTIP (enkel, hover-baserad) ─────────────────────────────────────────
function DSTooltip({ label, children }) {
  const [show, setShow] = useState(false);
  return <span style={{ position:"relative", display:"inline-block" }} onMouseEnter={()=>setShow(true)} onMouseLeave={()=>setShow(false)}>
    {children}
    {show && <span style={{ position:"absolute", bottom:"120%", left:"50%", transform:"translateX(-50%)", background:tokens.color.text, color:"#fff", fontSize:tokens.font.size.xs, padding:"5px 10px", borderRadius:tokens.radius.xs, whiteSpace:"nowrap", zIndex:tokens.zIndex.dropdown, boxShadow:tokens.shadow.md }}>{label}</span>}
  </span>;
}

// ── DS: DROPDOWN (enkel, klick-baserad) ────────────────────────────────────────
function DSDropdown({ trigger, children, align="left" }) {
  const [open, setOpen] = useState(false);
  return <div style={{ position:"relative", display:"inline-block" }}>
    <span onClick={()=>setOpen(o=>!o)}>{trigger}</span>
    {open && <>
      <div style={{ position:"fixed", inset:0, zIndex:tokens.zIndex.dropdown-1 }} onClick={()=>setOpen(false)} />
      <div className="ds-fade-in" style={{ position:"absolute", top:"110%", [align]:0, background:"#fff", border:`1px solid ${tokens.color.border}`, borderRadius:tokens.radius.md, boxShadow:tokens.shadow.md, zIndex:tokens.zIndex.dropdown, minWidth:180, padding:6 }}>
        {children}
      </div>
    </>}
  </div>;
}

// ── DS: SIDEBAR / SIDEBARSECTION / SIDEBARITEM ─────────────────────────────────
function DSSidebar({ children, width=250 }) {
  return <div style={{ width, background:tokens.color.primary, color:"#fff", padding:"28px 16px", display:"flex", flexDirection:"column", gap:4, boxSizing:"border-box" }}>{children}</div>;
}
function DSSidebarSection({ title, children }) {
  return <div style={{ marginBottom:18 }}>
    {title && <div style={{ fontSize:tokens.font.size.xs, fontWeight:tokens.font.weight.semibold, color:"rgba(255,255,255,0.4)", textTransform:"uppercase", letterSpacing:tokens.font.tracking.wide, padding:"0 14px", marginBottom:8 }}>{title}</div>}
    {children}
  </div>;
}
function DSSidebarItem({ icon, label, active=false, badge, onClick }) {
  return <div className={`ds-sidebar-item${active?" ds-sidebar-item--active":""}`} onClick={onClick} style={{
    display:"flex", alignItems:"center", gap:12, padding:"11px 14px", borderRadius:tokens.radius.sm, cursor:"pointer",
    fontSize:tokens.font.size.base, fontWeight: active?tokens.font.weight.bold:tokens.font.weight.medium,
    color: active?"#fff":"rgba(255,255,255,0.65)", background: active?tokens.alpha.hoverOnDarkStrong:"transparent",
    borderLeft: active?"3px solid #6fcf97":"3px solid transparent", transition:"all .15s ease",
  }}>
    <span style={{ width:18, textAlign:"center" }}>{icon}</span>
    <span style={{ flex:1, whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>{label}</span>
    {badge>0 && <span style={{ background:tokens.color.error, color:"#fff", borderRadius:tokens.radius.full, padding:"1px 7px", fontSize:11, fontWeight:tokens.font.weight.bold }}>{badge}</span>}
  </div>;
}

// ── DS: PAGE HEADER ────────────────────────────────────────────────────────────
function DSPageHeader({ breadcrumb, title, subtitle, actions }) {
  return <div style={{ marginBottom:32 }}>
    {breadcrumb && <div style={{ fontSize:tokens.font.size.xs, color:tokens.color.textMuted, marginBottom:8 }}>{breadcrumb}</div>}
    <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-end", gap:16 }}>
      <div>
        <h1 style={{ fontSize:tokens.font.size["3xl"], fontWeight:tokens.font.weight.extrabold, letterSpacing:tokens.font.tracking.tight, color:tokens.color.text, margin:"0 0 6px" }}>{title}</h1>
        {subtitle && <p style={{ fontSize:tokens.font.size.base, color:tokens.color.textMuted, margin:0 }}>{subtitle}</p>}
      </div>
      {actions && <div style={{ display:"flex", gap:10 }}>{actions}</div>}
    </div>
  </div>;
}

