// ── TOAST (ersätter alert()/confirm() för icke-blockerande bekräftelser) ──────
function toast(message, type="success") {
  window.dispatchEvent(new CustomEvent("rh-toast", { detail: { message, type } }));
}
function ToastContainer() {
  const [items, setItems] = useState([]);
  useEffect(() => {
    function onToast(e) {
      const id = Date.now() + Math.random();
      setItems(prev => [...prev, { id, ...e.detail }]);
      setTimeout(() => setItems(prev => prev.filter(t => t.id !== id)), 2600);
    }
    window.addEventListener("rh-toast", onToast);
    return () => window.removeEventListener("rh-toast", onToast);
  }, []);
  if (items.length === 0) return null;
  return <div style={{ position:"fixed", left:"50%", bottom:24, zIndex:300, display:"flex", flexDirection:"column", gap:8, alignItems:"center" }}>
    {items.map(t => <div key={t.id} style={{
      transform:"translateX(-50%)", position:"relative", left:"50%",
      background:t.type==="error"?"#7f1d1d":"#1a1a1a", color:"#fff", padding:"12px 18px", borderRadius:12,
      fontSize:13, fontWeight:600, display:"flex", alignItems:"center", gap:10, boxShadow:"0 8px 30px rgba(0,0,0,0.3)",
      maxWidth:"90vw", animation:"rh-toast-in .2s cubic-bezier(.34,1.56,.64,1)",
    }}>
      <span style={{ width:8, height:8, borderRadius:"50%", background:t.type==="error"?"#f87171":"#4ade80", flexShrink:0 }} />
      {t.message}
    </div>)}
  </div>;
}

